import "dart:io"; void main() { var lines = File("coverage/lcov.info").readAsLinesSync(); int totalLines = 0; int coveredLines = 0; bool skipFile = false; String currentFile = ""; Map<String, int> missingPerFile = {}; for(var line in lines) { if (line.startsWith("SF:")) { currentFile = line.substring(3); skipFile = currentFile.contains("app_localizations") || currentFile.contains("main.dart") || currentFile.contains("firebase_options.dart") || currentFile.contains(".g.dart") || currentFile.contains(".freezed.dart"); if (!missingPerFile.containsKey(currentFile) && !skipFile) { missingPerFile[currentFile] = 0; } continue; } if (skipFile) continue; if (line.startsWith("DA:")) { totalLines++; var parts = line.split(","); if (parts[1] != "0") { coveredLines++; } else { missingPerFile[currentFile] = missingPerFile[currentFile]! + 1; } } } print("Coverage: $coveredLines / $totalLines = ${(coveredLines/totalLines*100).toStringAsFixed(2)}%"); print("Missing lines by file:"); var sorted = missingPerFile.entries.toList()..sort((a,b) => b.value.compareTo(a.value)); for (var i=0; i<10; i++) { print("${sorted[i].key}: ${sorted[i].value} lines missing"); } }
